import React from 'react';
import { AppInfo } from '../types';
import PlusIcon from './icons/PlusIcon';

interface AppSelectorProps {
    apps: AppInfo[];
    limits: { [key: string]: number }; // limits in minutes
    onSetLimit: (appId: string, limit: number) => void;
    usage: { [key: string]: number }; // usage in seconds
    focusApps: string[];
    onToggleFocusApp: (appId: string) => void;
    isFocusing: boolean;
    onUpdateAppCategory: (appId: string, newCategory: string) => void;
    onOpenAddAppModal: () => void;
}

const formatTime = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
};

const AppSelector: React.FC<AppSelectorProps> = ({ 
    apps, limits, onSetLimit, usage, focusApps, onToggleFocusApp, isFocusing, onUpdateAppCategory, onOpenAddAppModal 
}) => {

    // Fix: Explicitly type the accumulator in the `reduce` function using generics to ensure `groupedApps` has the correct type.
    const groupedApps = apps.reduce<Record<string, AppInfo[]>>((acc, app) => {
        const category = app.category || 'Uncategorized';
        if (!acc[category]) {
            acc[category] = [];
        }
        acc[category].push(app);
        return acc;
    }, {});

    const allCategories = Object.keys(groupedApps).sort();

    const handleCategoryChange = (appId: string, newCategoryValue: string) => {
        if (newCategoryValue === '__CREATE_NEW__') {
            const newCategoryName = window.prompt("Enter the new category name:");
            if (newCategoryName && newCategoryName.trim()) {
                onUpdateAppCategory(appId, newCategoryName.trim());
            }
        } else {
            onUpdateAppCategory(appId, newCategoryValue);
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <div>
                    <h2 className="text-xl font-semibold mb-2">1. Select Apps to Block & Set Daily Limits</h2>
                    <p className="text-gray-400 mb-6">Use checkboxes to select apps for a temporary focus session. Use the inputs to set a permanent daily usage limit (in minutes).</p>
                </div>
                <button
                    onClick={onOpenAddAppModal}
                    className="flex-shrink-0 flex items-center justify-center bg-brand-accent hover:bg-brand-accent-hover text-white font-semibold py-2 px-4 rounded-lg transition-colors duration-200"
                    aria-label="Add custom app"
                >
                    <PlusIcon className="w-5 h-5 mr-2" />
                    Add App
                </button>
            </div>
            <div className="space-y-8">
                {(Object.entries(groupedApps) as [string, AppInfo[]][]).map(([category, appsInCategory]) => {
                    const categoryAppIds = appsInCategory.map(app => app.id);
                    const areAllSelected = categoryAppIds.every(id => focusApps.includes(id));

                    const handleToggleCategory = () => {
                        if (areAllSelected) {
                            // Deselect all in this category
                            categoryAppIds.forEach(id => {
                                if (focusApps.includes(id)) {
                                    onToggleFocusApp(id);
                                }
                            });
                        } else {
                            // Select all in this category
                            categoryAppIds.forEach(id => {
                                if (!focusApps.includes(id)) {
                                    onToggleFocusApp(id);
                                }
                            });
                        }
                    };

                    return (
                        <div key={category}>
                             <div className="flex items-center justify-between mb-4 border-b-2 border-gray-600 pb-2">
                                <h3 className="text-lg font-semibold text-gray-200">{category}</h3>
                                <div className="flex items-center">
                                    <label htmlFor={`select-all-${category.replace(/\s+/g, '-')}`} className="text-sm text-gray-400 mr-3 select-none cursor-pointer">
                                        Select All
                                    </label>
                                    <input
                                        type="checkbox"
                                        id={`select-all-${category.replace(/\s+/g, '-')}`}
                                        checked={areAllSelected}
                                        onChange={handleToggleCategory}
                                        disabled={isFocusing}
                                        className="h-5 w-5 rounded border-gray-500 bg-gray-800 text-brand-accent focus:ring-brand-accent focus:ring-offset-2 focus:ring-offset-brand-secondary transition cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
                                        aria-label={`Select all apps in ${category}`}
                                    />
                                </div>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {appsInCategory.map(app => {
                                    const usageSeconds = usage[app.id] || 0;
                                    const limitMinutes = limits[app.id] || 0;
                                    const limitSeconds = limitMinutes * 60;
                                    const progress = limitSeconds > 0 ? (usageSeconds / limitSeconds) * 100 : 0;
                                    const hasLimit = limitMinutes > 0;

                                    return (
                                        <div
                                            key={app.id}
                                            className="p-4 border-2 rounded-lg flex items-center justify-between transition-colors duration-200 bg-gray-700/50 border-gray-600"
                                        >
                                            <div className="flex items-center flex-grow mr-4">
                                                <div className="flex-shrink-0 mr-4">
                                                    <input
                                                        type="checkbox"
                                                        checked={focusApps.includes(app.id)}
                                                        onChange={() => onToggleFocusApp(app.id)}
                                                        disabled={isFocusing}
                                                        className="h-6 w-6 rounded border-gray-500 bg-gray-800 text-brand-accent focus:ring-brand-accent transition cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
                                                        aria-label={`Select ${app.name} for focus session`}
                                                    />
                                                </div>
                                                <app.Icon className="h-10 w-10 text-gray-300 flex-shrink-0" />
                                                <div className="w-full ml-4">
                                                    <span className="font-medium text-white">{app.name}</span>

                                                     <div className="mt-1">
                                                        <select
                                                            value={app.category}
                                                            onChange={(e) => handleCategoryChange(app.id, e.target.value)}
                                                            className="text-xs bg-gray-800 border border-gray-600 rounded-md py-1 px-2 text-gray-300 focus:outline-none focus:ring-1 focus:ring-brand-accent transition-colors w-full"
                                                            aria-label={`Category for ${app.name}`}
                                                        >
                                                            {allCategories.map(cat => (
                                                                <option key={cat} value={cat}>{cat}</option>
                                                            ))}
                                                            <option value="__CREATE_NEW__" className="text-brand-accent font-semibold">Create New...</option>
                                                        </select>
                                                    </div>

                                                    {hasLimit && (
                                                        <div className="w-full bg-gray-600 rounded-full h-2.5 mt-2">
                                                            <div
                                                                className={`h-2.5 rounded-full transition-all ${progress >= 100 ? 'bg-red-500' : 'bg-brand-accent'}`}
                                                                style={{ width: `${Math.min(progress, 100)}%` }}
                                                            ></div>
                                                        </div>
                                                    )}
                                                    <p className="text-xs text-gray-400 mt-1">
                                                        {hasLimit ? `${formatTime(usageSeconds)} / ${limitMinutes}m used today` : 'No daily limit set'}
                                                    </p>
                                                </div>
                                            </div>
                                            <div className="relative w-28 flex-shrink-0">
                                                <input
                                                    type="number"
                                                    min="0"
                                                    max="999"
                                                    placeholder="--"
                                                    aria-label={`Time limit for ${app.name} in minutes`}
                                                    value={limits[app.id] || ''}
                                                    onChange={(e) => onSetLimit(app.id, parseInt(e.target.value, 10) || 0)}
                                                    className="w-full bg-gray-800 border-2 border-gray-600 rounded-md py-2 pl-3 pr-10 text-white text-center placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-brand-accent transition-colors"
                                                />
                                                <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm pointer-events-none">min</span>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default AppSelector;

import React from 'react';
import ShieldCheckIcon from './icons/ShieldCheckIcon';

interface BlockPageProps {
    appName: string;
    onReturn: () => void;
    reason?: 'limit' | 'focus';
}

const BlockPage: React.FC<BlockPageProps> = ({ appName, onReturn, reason = 'limit' }) => {
    return (
        <div className="min-h-[calc(100vh-150px)] flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-brand-secondary p-8 rounded-lg shadow-2xl w-full max-w-2xl text-center">
                <ShieldCheckIcon className="h-20 w-20 mx-auto text-brand-accent mb-6" />

                <h1 className="text-4xl font-bold text-white mb-3">
                    {reason === 'focus' ? 'Focus Mode Active' : "Time's Up!"}
                </h1>
                <p className="text-lg text-gray-300 mb-8">
                    {reason === 'focus' ? (
                        <>
                            <span className="font-bold text-white">{appName}</span> is blocked during your focus session.
                        </>
                    ) : (
                        <>
                            You've reached your daily time limit for <span className="font-bold text-white">{appName}</span>.
                        </>
                    )}
                </p>

                <p className="text-gray-400 mb-8">
                    {reason === 'focus' 
                        ? "Stay focused on your goal! You can access this app after your session ends." 
                        : "Come back tomorrow for more. In the meantime, focus on your other goals!"}
                </p>

                <button
                    onClick={onReturn}
                    className="w-full max-w-xs mx-auto py-4 px-8 text-lg font-bold text-white bg-brand-accent hover:bg-brand-accent-hover rounded-lg transition duration-300 shadow-lg"
                >
                    Return to Dashboard
                </button>
            </div>
        </div>
    );
};

export default BlockPage;

import React, { useState, useEffect, useRef } from 'react';
import { AppInfo } from '../types';
import BlockPage from './BlockPage';

interface UsagePageProps {
    app: AppInfo;
    timeLimitSeconds: number;
    timeUsedSeconds: number;
    onLeave: (timeSpent: number) => void;
    isBlockedByFocus?: boolean;
}

const formatTime = (seconds: number): string => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.abs(seconds % 60);
    return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
};

const UsagePage: React.FC<UsagePageProps> = ({ app, timeLimitSeconds, timeUsedSeconds, onLeave, isBlockedByFocus = false }) => {
    const timeSpentInSessionRef = useRef(0);
    const timerRef = useRef<number | null>(null);
    const hasLimit = timeLimitSeconds > 0;
    const [isTimeUp, setIsTimeUp] = useState(false);
    const [blockReason, setBlockReason] = useState<'limit' | 'focus'>('limit');

    const [displayTime, setDisplayTime] = useState(
        hasLimit ? Math.max(0, timeLimitSeconds - timeUsedSeconds) : 0
    );

    // Handle immediate blocking if opened while blocked by focus session
    useEffect(() => {
        if (isBlockedByFocus) {
            setBlockReason('focus');
            setIsTimeUp(true);
            setTimeout(() => onLeave(timeSpentInSessionRef.current), 3000); // Give user a moment to see the block screen
        }
    }, [isBlockedByFocus, onLeave]);

    useEffect(() => {
        const initialTimeLeft = timeLimitSeconds - timeUsedSeconds;

        // Initial check for daily limit
        if (hasLimit && initialTimeLeft <= 0) {
            setBlockReason('limit');
            setIsTimeUp(true);
            setTimeout(() => onLeave(0), 3000);
            return;
        }

        if (isTimeUp) return; // Don't start timer if already blocked

        timerRef.current = window.setInterval(() => {
            timeSpentInSessionRef.current += 1;

            if (hasLimit) {
                // Countdown logic for limited sessions
                setDisplayTime(prev => {
                    const newTimeLeft = prev - 1;
                    if (newTimeLeft <= 0) {
                        if (timerRef.current) clearInterval(timerRef.current);
                        setBlockReason('limit');
                        setIsTimeUp(true);
                        setTimeout(() => onLeave(timeSpentInSessionRef.current), 3000);
                        return 0;
                    }
                    return newTimeLeft;
                });
            } else {
                // Count up logic for unlimited sessions
                setDisplayTime(prev => prev + 1);
            }
        }, 1000);

        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, [hasLimit, onLeave, timeLimitSeconds, timeUsedSeconds, isTimeUp]);

    const handleLeave = () => {
        onLeave(timeSpentInSessionRef.current);
    };

    if (isTimeUp) {
        return <BlockPage appName={app.name} onReturn={handleLeave} reason={blockReason} />;
    }

    return (
        <div className="min-h-[calc(100vh-150px)] flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-brand-secondary p-8 rounded-lg shadow-2xl w-full max-w-2xl text-center">
                <app.Icon className="h-20 w-20 mx-auto text-gray-300 mb-6" />

                <h1 className="text-3xl font-bold text-white mb-3">
                    Tracking Session for <span className="text-brand-accent">{app.name}</span>
                </h1>
                <p className="text-lg text-gray-300 mb-8">
                    Your usage is being timed. The app will be closed automatically after the time completes.
                </p>

                <div className="my-8">
                    <p className="text-sm text-gray-400 uppercase tracking-wider">
                        {hasLimit ? 'Time Remaining' : 'Time Spent'}
                    </p>
                    <p className={`text-6xl font-mono font-bold tracking-tighter mt-2 ${(displayTime <= 60 && hasLimit && displayTime > 0) ? 'text-red-500 animate-pulse' : 'text-white'}`}>
                        {formatTime(displayTime)}
                    </p>
                </div>

                <button
                    onClick={handleLeave}
                    className="w-full max-w-xs mx-auto py-4 px-8 text-lg font-bold text-white bg-red-600 hover:bg-red-700 rounded-lg transition duration-300 shadow-lg"
                >
                    End Session
                </button>
            </div>
        </div>
    );
};

export default UsagePage;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { INITIAL_SOCIAL_APPS, BADGES } from '../constants';
import AppSelector from './AppSelector';
import InsightsChart from './InsightsChart';
import { getNewProductiveSuggestions } from '../services/geminiService';
import { ProductiveSuggestion, AppInfo, ChartDataPoint, FocusSession, UserProgress } from '../types';
import ProductiveSuggestions from './ProductiveSuggestions';
import { playBlockSound, playSound, SoundName } from '../utils/audioUtils';
import AppLauncher from './AppLauncher';
import UsagePage from './UsagePage';
import FocusSessionControl from './FocusSessionControl';
import Notification from './Notification';
import { createFocusBlockPageHTML, createDailyLimitBlockPageHTML } from '../utils/blockPageUtils';
import Features from './Features';
import FocusHistory from './FocusHistory';
import { useIdleTimer } from '../utils/idleTimer';
import AddAppModal from './AddAppModal';
import GlobeIcon from './icons/GlobeIcon';
import GamificationHub from './GamificationHub';

// Types for new dynamic data structure
interface HourlyStats {
    [hour: number]: { focus: number, distraction: number };
}

interface TodayStats {
    date: string;
    hourly: HourlyStats;
}

interface DailyStats {
    [date: string]: { focus: number, distraction: number };
}

type InsightsView = 'day' | 'week' | 'month';
type MainView = 'dashboard' | 'usage';

interface DashboardProps {
    isSoundEnabled: boolean;
    userProgress: UserProgress;
    onUpdateProgress: (newProgress: UserProgress) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isSoundEnabled, userProgress, onUpdateProgress }) => {
    const [apps, setApps] = useState<AppInfo[]>(() => {
        try {
            const savedApps = window.localStorage.getItem('focusFlowApps');
            return savedApps ? JSON.parse(savedApps) : INITIAL_SOCIAL_APPS;
        } catch (error) {
            console.error("Failed to parse apps from localStorage", error);
            return INITIAL_SOCIAL_APPS;
        }
    });

    const [appLimits, setAppLimits] = useState<{ [key: string]: number }>(() => {
        try {
            const savedLimits = window.localStorage.getItem('focusFlowAppLimits');
            return savedLimits ? JSON.parse(savedLimits) : {};
        } catch (error) {
            console.error("Failed to parse app limits from localStorage", error);
            return {};
        }
    });

    const [appUsage, setAppUsage] = useState<{ [key: string]: number }>(() => {
        try {
            const savedUsageData = window.localStorage.getItem('focusFlowAppUsage');
            if (!savedUsageData) return {};

            const { usage, date } = JSON.parse(savedUsageData);
            const today = new Date().toISOString().split('T')[0];

            return date === today ? usage : {};
        } catch (error) {
            console.error("Failed to parse app usage from localStorage", error);
            return {};
        }
    });

    const [productiveSuggestions, setProductiveSuggestions] = useState<ProductiveSuggestion[]>([]);
    const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(true);
    const [insightsView, setInsightsView] = useState<InsightsView>('week');
    const [currentView, setCurrentView] = useState<MainView>('dashboard');
    const [activeApp, setActiveApp] = useState<AppInfo | null>(null);
    const [isAddAppModalOpen, setIsAddAppModalOpen] = useState(false);

    // Dynamic focus data states
    const [dailyStats, setDailyStats] = useState<DailyStats>({});
    const [todayStats, setTodayStats] = useState<TodayStats>({ date: '', hourly: {} });
    const [focusHistory, setFocusHistory] = useState<FocusSession[]>([]);

    // Focus Session State
    const [isFocusing, setIsFocusing] = useState(false);
    const [isIdle, setIsIdle] = useState(false);
    const [idleTimeout, setIdleTimeout] = useState(300); // 5 minutes, 0 to disable
    const [focusApps, setFocusApps] = useState<string[]>([]);
    const [focusDuration, setFocusDuration] = useState(25 * 60);
    const [timeLeft, setTimeLeft] = useState(25 * 60);
    const [focusGoal, setFocusGoal] = useState('');
    const [syncToCalendar, setSyncToCalendar] = useState(false);
    const [sessionWasSynced, setSessionWasSynced] = useState(false);
    const [notification, setNotification] = useState<{message: string, type: 'success' | 'info' | 'calendar' | 'block' | 'achievement', app?: AppInfo, badgeName?: string} | null>(null);
    const [focusStartSound, setFocusStartSound] = useState<SoundName>('Bell');
    const [focusEndSound, setFocusEndSound] = useState<SoundName>('Chime');
    const focusIntervalRef = useRef<number | null>(null);
    const appWindowRef = useRef<Window | null>(null);

    // Idle timer hook
    useIdleTimer({
        onIdle: () => {
            if (isFocusing && !isIdle) {
                setIsIdle(true);
            }
        },
        onActive: () => {
            if (isFocusing && isIdle) {
                setIsIdle(false);
            }
        },
        timeout: idleTimeout,
        enabled: isFocusing && idleTimeout > 0,
    });

    // Effect to pause/resume timer based on idle state
    useEffect(() => {
        if (!isFocusing) {
            if (isIdle) setIsIdle(false);
            return;
        }

        if (isIdle) {
            // PAUSE: User is idle, and we are focusing.
            if (focusIntervalRef.current) {
                clearInterval(focusIntervalRef.current);
                focusIntervalRef.current = null;
                setNotification({ message: 'Session paused due to inactivity. Move your mouse or type to resume.', type: 'info' });
            }
        } else {
            // RESUME: User is not idle (or just became active), and we are focusing.
            // Check if the timer needs to be (re)started.
            if (!focusIntervalRef.current && timeLeft > 0) {
                focusIntervalRef.current = window.setInterval(() => {
                    setTimeLeft(prev => prev - 1);
                }, 1000);
                setNotification({ message: 'Focus session resumed.', type: 'info' });
                setTimeout(() => setNotification(null), 4000);
            }
        }
    }, [isFocusing, isIdle]);

    // Load dynamic focus data from localStorage on mount
    useEffect(() => {
        const todayStr = new Date().toISOString().split('T')[0];

        try {
            const savedDailyStats = window.localStorage.getItem('focusFlowDailyStats');
            if (savedDailyStats) setDailyStats(JSON.parse(savedDailyStats));
        } catch (e) { console.error("Failed to load daily stats", e); }

        try {
            const savedTodayStats = window.localStorage.getItem('focusFlowTodayStats');
            if (savedTodayStats) {
                const parsed: TodayStats = JSON.parse(savedTodayStats);
                if (parsed.date === todayStr) {
                    setTodayStats(parsed);
                } else {
                    const newTodayStats = { date: todayStr, hourly: {} };
                    setTodayStats(newTodayStats);
                    window.localStorage.setItem('focusFlowTodayStats', JSON.stringify(newTodayStats));
                }
            } else {
                const newTodayStats = { date: todayStr, hourly: {} };
                setTodayStats(newTodayStats);
                window.localStorage.setItem('focusFlowTodayStats', JSON.stringify(newTodayStats));
            }
        } catch (e) { console.error("Failed to load today's stats", e); }

        try {
            const savedHistory = window.localStorage.getItem('focusFlowHistory');
            if (savedHistory) setFocusHistory(JSON.parse(savedHistory));
        } catch (e) { console.error("Failed to load focus history", e); }
    }, []);

    // Save app configuration to localStorage whenever it changes
    useEffect(() => {
        try {
            window.localStorage.setItem('focusFlowApps', JSON.stringify(apps));
        } catch (error) {
            console.error("Failed to save apps to localStorage", error);
        }
    }, [apps]);

    // Save app limits to localStorage whenever they change
    useEffect(() => {
        try {
            window.localStorage.setItem('focusFlowAppLimits', JSON.stringify(appLimits));
        } catch (error) {
            console.error("Failed to save app limits to localStorage", error);
        }
    }, [appLimits]);

    // Save app usage to localStorage whenever it changes, with a daily reset mechanism
    useEffect(() => {
        try {
            const today = new Date().toISOString().split('T')[0];
            const dataToSave = {
                usage: appUsage,
                date: today
            };
            window.localStorage.setItem('focusFlowAppUsage', JSON.stringify(dataToSave));
        } catch (error) {
            console.error("Failed to save app usage to localStorage", error);
        }
    }, [appUsage]);

    // Save focus history to localStorage
    useEffect(() => {
        try {
            window.localStorage.setItem('focusFlowHistory', JSON.stringify(focusHistory));
        } catch (error) {
            console.error("Failed to save focus history to localStorage", error);
        }
    }, [focusHistory]);

    // Fetch productive suggestions on mount
    useEffect(() => {
        const fetchSuggestions = async () => {
            setIsLoadingSuggestions(true);
            const suggestions = await getNewProductiveSuggestions();
            setProductiveSuggestions(suggestions);
            setIsLoadingSuggestions(false);
        };
        fetchSuggestions();
    }, []);

    const allCategories = useMemo(() => {
        const categories = new Set(apps.map(app => app.category));
        return Array.from(categories).sort();
    }, [apps]);

    const handleAddNewApp = (newApp: { name: string; url: string; category: string }) => {
        const newAppInfo: AppInfo = {
            id: `custom-${new Date().getTime()}`, // simple unique ID
            name: newApp.name,
            url: newApp.url,
            category: newApp.category,
            Icon: GlobeIcon, // Generic icon for custom apps
        };
        setApps(prevApps => [...prevApps, newAppInfo]);
        setIsAddAppModalOpen(false);
    };

    const handleUpdateAppCategory = (appId: string, newCategory: string) => {
        setApps(prevApps => 
            prevApps.map(app => 
                app.id === appId ? { ...app, category: newCategory } : app
            )
        );
    };

    const handleFocusEnd = useCallback((wasStopped = false) => {
        setIsFocusing(false);
        if (focusIntervalRef.current) {
            clearInterval(focusIntervalRef.current);
            focusIntervalRef.current = null;
        }

        if (isSoundEnabled) {
            playSound(focusEndSound);
        }

        const minutesFocused = Math.floor((focusDuration - timeLeft) / 60);

        if (minutesFocused > 0) {
            const now = new Date();
            const todayStr = now.toISOString().split('T')[0];
            const currentHour = now.getHours();

            setDailyStats(prev => {
                const newStats = { ...prev };
                if (!newStats[todayStr]) newStats[todayStr] = { focus: 0, distraction: 0 };
                newStats[todayStr].focus += minutesFocused;
                window.localStorage.setItem('focusFlowDailyStats', JSON.stringify(newStats));
                return newStats;
            });

            setTodayStats(prev => {
                const newStats = { ...prev, hourly: { ...prev.hourly } };
                if (newStats.date !== todayStr) { // Day rollover check
                    newStats.date = todayStr;
                    newStats.hourly = {};
                }
                if (!newStats.hourly[currentHour]) newStats.hourly[currentHour] = { focus: 0, distraction: 0 };
                newStats.hourly[currentHour].focus += minutesFocused;
                window.localStorage.setItem('focusFlowTodayStats', JSON.stringify(newStats));
                return newStats;
            });

            // GAMIFICATION LOGIC
            const pointsEarned = Math.floor(minutesFocused * 1); // 1 point per minute
            const newTotalFocusMinutes = userProgress.totalFocusMinutes + minutesFocused;
            const newSessionsCompleted = userProgress.sessionsCompleted + 1;

            // Streak Logic
            let newStreak = userProgress.streak;
            if (userProgress.lastActiveDate !== todayStr) {
                const yesterday = new Date();
                yesterday.setDate(yesterday.getDate() - 1);
                const yesterdayStr = yesterday.toISOString().split('T')[0];

                if (userProgress.lastActiveDate === yesterdayStr) {
                    newStreak += 1; // Consecutive day
                } else if (userProgress.streak === 0 || userProgress.lastActiveDate === '') {
                    newStreak = 1; // First day or restart
                } else {
                    newStreak = 1; // Broken streak
                }
            } else if (userProgress.streak === 0) {
                 newStreak = 1; // First session of the day, but streak was 0
            }

            // Check for new badges
            const currentBadgeIds = new Set(userProgress.badges);
            const newBadges: string[] = [];

            const tempStats: UserProgress = {
                ...userProgress,
                totalFocusMinutes: newTotalFocusMinutes,
                sessionsCompleted: newSessionsCompleted,
                streak: newStreak,
                points: userProgress.points + pointsEarned
            };

            BADGES.forEach(badge => {
                if (!currentBadgeIds.has(badge.id)) {
                    if (badge.condition(tempStats)) {
                        newBadges.push(badge.id);
                        currentBadgeIds.add(badge.id);
                    }
                }
            });

            // Update Progress
            onUpdateProgress({
                ...tempStats,
                badges: Array.from(currentBadgeIds),
                lastActiveDate: todayStr
            });

            // Trigger Notifications for Badges
            newBadges.forEach((badgeId, index) => {
                const badge = BADGES.find(b => b.id === badgeId);
                if (badge) {
                    setTimeout(() => {
                        setNotification({
                            message: `Badge Unlocked: ${badge.name}`,
                            type: 'achievement',
                            badgeName: badge.name
                        });
                        if (isSoundEnabled) playSound('Chime');
                    }, 1000 + (index * 3000));
                }
            });
        }

        const sessionToAdd: FocusSession = {
            id: new Date().toISOString(),
            goal: focusGoal,
            duration: focusDuration,
            completedDuration: focusDuration - timeLeft,
            date: new Date().toISOString(),
            appsBlocked: focusApps,
            status: wasStopped ? 'stopped' : 'completed',
            interventions: []
        };
        setFocusHistory(prev => [...prev, sessionToAdd]);

        let relevantApp: AppInfo | undefined = undefined;
        if (focusApps.length === 1) {
            relevantApp = apps.find(app => app.id === focusApps[0]);
        }

        if (sessionWasSynced) {
            setNotification({ 
                message: `Calendar event for "${focusGoal}" updated. Great work!`, 
                type: 'success',
                app: relevantApp
            });
        } else {
             setNotification({ 
                message: `You completed a ${minutesFocused}-minute focus session.`, 
                type: 'success',
                app: relevantApp
            });
        }

        // Reset for next session
        setFocusGoal('');
        setSyncToCalendar(false);
        setSessionWasSynced(false);
        setIsIdle(false);

        setTimeout(() => setNotification(null), 5000);
    }, [focusDuration, timeLeft, sessionWasSynced, focusGoal, isSoundEnabled, focusEndSound, focusApps, apps, userProgress, onUpdateProgress]);

     // Timer effect for focus session
     useEffect(() => {
        if (isFocusing && timeLeft <= 0) {
            handleFocusEnd();
        }
    }, [timeLeft, isFocusing, handleFocusEnd]);

    const handleSetAppLimit = (appId: string, limit: number) => {
        setAppLimits(prev => ({
            ...prev,
            [appId]: limit,
        }));
    };

    const handleToggleFocusApp = (appId: string) => {
        setFocusApps(prev => 
            prev.includes(appId) ? prev.filter(id => id !== appId) : [...prev, appId]
        );
    };

    const handleStartFocus = () => {
        if (focusIntervalRef.current) clearInterval(focusIntervalRef.current);
        setTimeLeft(focusDuration);
        setIsFocusing(true);
        setIsIdle(false);
        setSessionWasSynced(syncToCalendar);

        if (isSoundEnabled) {
            playSound(focusStartSound);
        }

        focusIntervalRef.current = window.setInterval(() => {
            setTimeLeft(prev => prev - 1);
        }, 1000);

        if (syncToCalendar) {
            setNotification({ 
                message: `Your session for "${focusGoal}" is now on your calendar.`, 
                type: 'calendar' 
            });
        } else {
            setNotification({ message: 'Focus session started. Good luck!', type: 'info' });
        }
        setTimeout(() => setNotification(null), 5000);
    };

    const handleStopFocus = () => {
        handleFocusEnd(true);
    };

    const handleAppLaunchAttempt = (appId: string) => {
        const app = apps.find(a => a.id === appId);
        if (!app) return;

        if (isFocusing && focusApps.includes(appId)) {
            if (isSoundEnabled) playBlockSound();
            const blockPageHTML = createFocusBlockPageHTML(focusGoal, timeLeft);
            const newWindow = window.open('', '_blank');
            if (newWindow) {
                newWindow.document.write(blockPageHTML);
                newWindow.document.close();
            } else {
                alert("Please disable your pop-up blocker to see the block notification.");
            }
             setNotification({
                message: `This app is blocked during your "${focusGoal || 'focus'}" session.`,
                type: 'block',
                app: app
            });
            setTimeout(() => setNotification(null), 5000);
            return;
        }

        const limitInSeconds = (appLimits[appId] || 0) * 60;
        const usageInSeconds = appUsage[appId] || 0;

        if (limitInSeconds > 0 && usageInSeconds >= limitInSeconds) {
            if (isSoundEnabled) playBlockSound();
            const blockPageHTML = createDailyLimitBlockPageHTML(app.name);
            const newWindow = window.open('', '_blank');
            if (newWindow) {
                newWindow.document.write(blockPageHTML);
                newWindow.document.close();
            } else {
                alert("Please disable your pop-up blocker to see the block notification.");
            }
            setNotification({
                message: `You've used all your daily time.`,
                type: 'block',
                app: app
            });
            setTimeout(() => setNotification(null), 5000);
        } else {
            setActiveApp(app);
            appWindowRef.current = window.open(app.url, '_blank', 'noopener,noreferrer');
            setCurrentView('usage');
        }
    };

    const handleLeaveUsagePage = useCallback((timeSpentSeconds: number) => {
        if (!activeApp) return;

        const usageInMinutes = Math.round(timeSpentSeconds / 60);

        if (usageInMinutes > 0) {
            const now = new Date();
            const todayStr = now.toISOString().split('T')[0];
            const currentHour = now.getHours();

            setDailyStats(prev => {
                const newStats = { ...prev };
                if (!newStats[todayStr]) newStats[todayStr] = { focus: 0, distraction: 0 };
                newStats[todayStr].distraction += usageInMinutes;
                window.localStorage.setItem('focusFlowDailyStats', JSON.stringify(newStats));
                return newStats;
            });

            setTodayStats(prev => {
                const newStats = { ...prev, hourly: { ...prev.hourly } };
                 if (newStats.date !== todayStr) { // Day rollover check
                    newStats.date = todayStr;
                    newStats.hourly = {};
                }
                if (!newStats.hourly[currentHour]) newStats.hourly[currentHour] = { focus: 0, distraction: 0 };
                newStats.hourly[currentHour].distraction += usageInMinutes;
                window.localStorage.setItem('focusFlowTodayStats', JSON.stringify(newStats));
                return newStats;
            });
        }

        setAppUsage(prev => ({
            ...prev,
            [activeApp.id]: (prev[activeApp.id] || 0) + timeSpentSeconds,
        }));

        if (appWindowRef.current && !appWindowRef.current.closed) {
            try {
                appWindowRef.current.close();
            } catch (e) {
                console.error("Could not close app window.", e);
            }
        }
        appWindowRef.current = null;

        setCurrentView('dashboard');
        setActiveApp(null);
    }, [activeApp]);

    const chartData = useMemo(() => {
        const now = new Date();

        if (insightsView === 'day') {
            const data: ChartDataPoint[] = [];
            for (let hour = 6; hour <= 22; hour++) {
                const stats = todayStats.hourly[hour] || { focus: 0, distraction: 0 };
                const period = hour < 12 ? 'a' : 'p';
                let displayHour = hour % 12;
                if (displayHour === 0) displayHour = 12;
                data.push({ hour: `${displayHour}${period}`, ...stats });
            }
            return data;
        }

        if (insightsView === 'week') {
            const data: ChartDataPoint[] = [];
            const dayMap = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
            const currentDayOfWeek = now.getDay();

            for (let i = 0; i < 7; i++) {
                const dayOfView = new Date(now);
                dayOfView.setDate(now.getDate() - (currentDayOfWeek - i));
                dayOfView.setHours(0, 0, 0, 0);
                const dateStr = dayOfView.toISOString().split('T')[0];
                const stats = dailyStats[dateStr] || { focus: 0, distraction: 0 };
                data.push({ day: dayMap[i], ...stats });
            }
            return data;
        }

        if (insightsView === 'month') {
            const data: ChartDataPoint[] = [];
            const year = now.getFullYear();
            const month = now.getMonth();
            const todayDate = now.getDate();

            for (let day = 1; day <= todayDate; day++) {
                const dayDate = new Date(year, month, day);
                const dateStr = dayDate.toISOString().split('T')[0];
                const stats = dailyStats[dateStr] || { focus: 0, distraction: 0 };
                data.push({ day: String(day), ...stats });
            }
            return data;
        }

        return [];
    }, [insightsView, dailyStats, todayStats]);

    const renderChart = () => {
        const key = insightsView === 'day' ? 'hour' : 'day';
        return <InsightsChart data={chartData} xAxisDataKey={key} />;
    }

    const ViewButton: React.FC<{view: InsightsView, label: string}> = ({ view, label }) => (
        <button
            onClick={() => setInsightsView(view)}
            className={`px-3 py-1 text-sm font-medium rounded-md transition-colors ${
                insightsView === view ? 'bg-brand-accent text-white' : 'text-gray-300 hover:bg-gray-600'
            }`}
        >
            {label}
        </button>
    );

    if (currentView === 'usage' && activeApp) {
        const limitInSeconds = (appLimits[activeApp.id] || 0) * 60;
        const usageInSeconds = appUsage[activeApp.id] || 0;
        const isBlockedByFocus = isFocusing && focusApps.includes(activeApp.id);

        return (
            <UsagePage
                app={activeApp}
                timeLimitSeconds={limitInSeconds}
                timeUsedSeconds={usageInSeconds}
                onLeave={handleLeaveUsagePage}
                isBlockedByFocus={isBlockedByFocus}
            />
        );
    }

    return (
        <div className="space-y-8 p-4">
            {notification && (
                <Notification
                    message={notification.message}
                    type={notification.type}
                    app={notification.app}
                    onClose={() => setNotification(null)}
                    badgeName={notification.badgeName}
                />
            )}
            <AddAppModal 
                isOpen={isAddAppModalOpen}
                onClose={() => setIsAddAppModalOpen(false)}
                onAddApp={handleAddNewApp}
                existingCategories={allCategories}
            />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-brand-secondary p-6 rounded-lg shadow-lg">
                    <h1 className="text-3xl font-bold mb-2">Your Digital Wellbeing Hub</h1>
                    <p className="text-gray-400 mb-6">Manage your screen time by setting daily limits and starting focus sessions to block distracting apps.</p>

                    <div className="space-y-8">
                       <AppSelector 
                           apps={apps}
                           limits={appLimits}
                           onSetLimit={handleSetAppLimit}
                           usage={appUsage}
                           focusApps={focusApps}
                           onToggleFocusApp={handleToggleFocusApp}
                           isFocusing={isFocusing}
                           onUpdateAppCategory={handleUpdateAppCategory}
                           onOpenAddAppModal={() => setIsAddAppModalOpen(true)}
                       />
                       <FocusSessionControl 
                           isFocusing={isFocusing}
                           onStart={handleStartFocus}
                           onStop={handleStopFocus}
                           timeLeft={timeLeft}
                           hasSelectedApps={focusApps.length > 0}
                           goal={focusGoal}
                           onGoalChange={setFocusGoal}
                           duration={focusDuration}
                           onDurationChange={setFocusDuration}
                           syncToCalendar={syncToCalendar}
                           onSyncToCalendarChange={setSyncToCalendar}
                           startSound={focusStartSound}
                           onStartSoundChange={setFocusStartSound}
                           endSound={focusEndSound}
                           onEndSoundChange={setFocusEndSound}
                           isIdle={isIdle}
                           idleTimeout={idleTimeout}
                           onIdleTimeoutChange={setIdleTimeout}
                       />
                    </div>
                </div>

                <div className="lg:col-span-1 space-y-8">
                   <GamificationHub progress={userProgress} />

                   <div className="bg-brand-secondary p-6 rounded-lg shadow-lg">
                        <div className="flex justify-between items-center mb-4">
                            <h2 className="text-xl font-bold">Focus Insights</h2>
                            <div className="flex space-x-1 bg-gray-800 p-1 rounded-lg">
                               <ViewButton view="day" label="Day" />
                               <ViewButton view="week" label="Week" />
                               <ViewButton view="month" label="Month" />
                            </div>
                        </div>
                        {renderChart()}
                    </div>
                    <ProductiveSuggestions suggestions={productiveSuggestions} isLoading={isLoadingSuggestions} />
                    <FocusHistory sessions={focusHistory} apps={apps} />
                </div>
            </div>

            <AppLauncher apps={apps} onAppClick={handleAppLaunchAttempt} />

            <Features />
        </div>
    );
};

