import React from 'react';
import { AppInfo } from '../types';
import PlusIcon from './icons/PlusIcon';

interface AppSelectorProps {
    apps: AppInfo[];
    limits: { [key: string]: number }; // limits in minutes
    onSetLimit: (appId: string, limit: number) => void;
    usage: { [key: string]: number }; // usage in seconds
    focusApps: string[];
    onToggleFocusApp: (appId: string) => void;
    isFocusing: boolean;
    onUpdateAppCategory: (appId: string, newCategory: string) => void;
    onOpenAddAppModal: () => void;
}

const formatTime = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
};

const AppSelector: React.FC<AppSelectorProps> = ({ 
    apps, limits, onSetLimit, usage, focusApps, onToggleFocusApp, isFocusing, onUpdateAppCategory, onOpenAddAppModal 
}) => {

    const groupedApps = apps.reduce((acc, app) => {
        const category = app.category || 'Uncategorized';
        if (!acc[category]) {
            acc[category] = [];
        }
        acc[category].push(app);
        return acc;
    }, {} as Record<string, AppInfo[]>);

    const allCategories = Object.keys(groupedApps).sort();

    const handleCategoryChange = (appId: string, newCategoryValue: string) => {
        if (newCategoryValue === '__CREATE_NEW__') {
            const newCategoryName = window.prompt("Enter the new category name:");
            if (newCategoryName && newCategoryName.trim()) {
                onUpdateAppCategory(appId, newCategoryName.trim());
            }
        } else {
            onUpdateAppCategory(appId, newCategoryValue);
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <div>
                    <h2 className="text-xl font-semibold mb-2">1. Select Apps to Block & Set Daily Limits</h2>
                    <p className="text-gray-400 mb-6">Use checkboxes for focus sessions. Set daily usage limits to control habits.</p>
                </div>
                <button
                    onClick={onOpenAddAppModal}
                    className="flex-shrink-0 flex items-center justify-center bg-brand-accent hover:bg-brand-accent-hover text-white font-semibold py-2 px-4 rounded-lg transition-colors duration-200"
                    aria-label="Add custom app"
                >
                    <PlusIcon className="w-5 h-5 mr-2" />
                    Add App
                </button>
            </div>
            <div className="space-y-8">
                {(Object.entries(groupedApps) as [string, AppInfo[]][]).map(([category, appsInCategory]) => {
                    const categoryAppIds = appsInCategory.map(app => app.id);
                    const areAllSelected = categoryAppIds.every(id => focusApps.includes(id));

                    const handleToggleCategory = () => {
                        if (areAllSelected) {
                            // Deselect all in this category
                            categoryAppIds.forEach(id => {
                                if (focusApps.includes(id)) {
                                    onToggleFocusApp(id);
                                }
                            });
                        } else {
                            // Select all in this category
                            categoryAppIds.forEach(id => {
                                if (!focusApps.includes(id)) {
                                    onToggleFocusApp(id);
                                }
                            });
                        }
                    };

                    return (
                        <div key={category}>
                             <div className="flex items-center justify-between mb-4 border-b-2 border-gray-600 pb-2">
                                <h3 className="text-lg font-semibold text-gray-200">{category}</h3>
                                <div className="flex items-center">
                                    <label htmlFor={`select-all-${category.replace(/\s+/g, '-')}`} className="text-sm text-gray-400 mr-3 select-none cursor-pointer">
                                        Select All
                                    </label>
                                    <input
                                        type="checkbox"
                                        id={`select-all-${category.replace(/\s+/g, '-')}`}
                                        checked={areAllSelected}
                                        onChange={handleToggleCategory}
                                        disabled={isFocusing}
                                        className="h-5 w-5 rounded border-gray-500 bg-gray-800 text-brand-accent focus:ring-brand-accent focus:ring-offset-2 focus:ring-offset-brand-secondary transition cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
                                        aria-label={`Select all apps in ${category}`}
                                    />
                                </div>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {appsInCategory.map(app => {
                                    const usageSeconds = usage[app.id] || 0;
                                    const limitMinutes = limits[app.id] || 0;
                                    const limitSeconds = limitMinutes * 60;
                                    const progress = limitSeconds > 0 ? (usageSeconds / limitSeconds) * 100 : 0;
                                    const hasLimit = limitMinutes > 0;
                                    const isLimitReached = hasLimit && progress >= 100;

                                    return (
                                        <div
                                            key={app.id}
                                            className={`p-4 border-2 rounded-lg flex items-center justify-between transition-colors duration-200 bg-gray-700/50 ${isLimitReached ? 'border-red-500/50 bg-red-900/10' : 'border-gray-600'}`}
                                        >
                                            <div className="flex items-center flex-grow mr-4 overflow-hidden">
                                                <div className="flex-shrink-0 mr-4">
                                                    <input
                                                        type="checkbox"
                                                        checked={focusApps.includes(app.id)}
                                                        onChange={() => onToggleFocusApp(app.id)}
                                                        disabled={isFocusing}
                                                        className="h-6 w-6 rounded border-gray-500 bg-gray-800 text-brand-accent focus:ring-brand-accent transition cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
                                                        aria-label={`Select ${app.name} for focus session`}
                                                    />
                                                </div>
                                                <app.Icon className="h-10 w-10 text-gray-300 flex-shrink-0" />
                                                <div className="w-full ml-4 overflow-hidden">
                                                    <span className="font-medium text-white truncate block">{app.name}</span>

                                                     <div className="mt-1">
                                                        <select
                                                            value={app.category}
                                                            onChange={(e) => handleCategoryChange(app.id, e.target.value)}
                                                            className="text-xs bg-gray-800 border border-gray-600 rounded-md py-1 px-2 text-gray-300 focus:outline-none focus:ring-1 focus:ring-brand-accent transition-colors w-full max-w-[140px]"
                                                            aria-label={`Category for ${app.name}`}
                                                        >
                                                            {allCategories.map(cat => (
                                                                <option key={cat} value={cat}>{cat}</option>
                                                            ))}
                                                            <option value="__CREATE_NEW__" className="text-brand-accent font-semibold">Create New...</option>
                                                        </select>
                                                    </div>

                                                    {hasLimit && (
                                                        <div className="w-full bg-gray-600 rounded-full h-1.5 mt-2">
                                                            <div
                                                                className={`h-1.5 rounded-full transition-all ${isLimitReached ? 'bg-red-500' : 'bg-brand-accent'}`}
                                                                style={{ width: `${Math.min(progress, 100)}%` }}
                                                            ></div>
                                                        </div>
                                                    )}
                                                    <p className={`text-xs mt-1 ${isLimitReached ? 'text-red-400 font-semibold' : 'text-gray-400'}`}>
                                                        {hasLimit ? `${formatTime(usageSeconds)} / ${limitMinutes}m` : 'No daily limit'}
                                                    </p>
                                                </div>
                                            </div>

                                            {/* Enhanced Daily Limit Input */}
                                            <div className="flex flex-col items-end">
                                                <label htmlFor={`limit-${app.id}`} className="text-[10px] text-gray-400 mb-1 uppercase tracking-wider font-semibold">Daily Limit</label>
                                                <div className="relative w-24 flex-shrink-0">
                                                    <input
                                                        id={`limit-${app.id}`}
                                                        type="number"
                                                        min="0"
                                                        max="1440"
                                                        placeholder="∞"
                                                        aria-label={`Daily time limit for ${app.name} in minutes`}
                                                        value={limits[app.id] > 0 ? limits[app.id] : ''}
                                                        onChange={(e) => {
                                                            const val = e.target.value;
                                                            const num = val === '' ? 0 : parseInt(val, 10);
                                                            if (!isNaN(num) && num >= 0) {
                                                                onSetLimit(app.id, num);
                                                            }
                                                        }}
                                                        className={`w-full bg-gray-800 border-2 rounded-md py-1.5 pl-2 pr-8 text-white text-right placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-brand-accent transition-colors text-sm ${isLimitReached ? 'border-red-500 text-red-100 placeholder-red-300' : 'border-gray-600'}`}
                                                    />
                                                    <span className={`absolute right-2 top-1/2 -translate-y-1/2 text-xs pointer-events-none ${isLimitReached ? 'text-red-300' : 'text-gray-400'}`}>min</span>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default AppSelector;

payload.text:
To implement a real-time backend for **FocusFlow AI** using Node.js, Express, and Socket.io, follow this step-by-step technical guide. Note that this backend should be hosted on a service like **Railway**, **Render**, or **Heroku**.

### Step 1: Initialize the Project
On your local machine, create a new folder and initialize it.

```bash
mkdir focusflow-backend
cd focusflow-backend
npm init -y
npm install express socket.io @google/genai dotenv cors pg
npm install --save-dev typescript @types/express @types/node ts-node
npx tsc --init
```

### Step 2: Database Setup (PostgreSQL)
If you use **Supabase** or **Neon**, you get a connection string. Create a table for sessions:

```sql
CREATE TABLE focus_sessions (
    id SERIAL PRIMARY KEY,
    user_id TEXT NOT NULL,
    goal TEXT,
    duration INTEGER,
    status TEXT DEFAULT 'active',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
```

### Step 3: Create the Server (`server.ts`)
This script handles the API, the AI, and the Real-time WebSockets.

```typescript
import express from 'express';
import { createServer } from 'http';
import { Server } from 'socket.io';
import { GoogleGenAI } from '@google/genai';
import dotenv from 'dotenv';
import cors from 'cors';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: { origin: "*" } // In production, limit this to your frontend URL
});

// 1. Secure AI Route
app.post('/api/get-suggestions', async (req, res) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Suggest 3 productive alternatives to scrolling social media."
    });
    res.json({ text: response.text });
  } catch (error) {
    res.status(500).json({ error: "AI failed" });
  }
});

// 2. Real-time WebSocket Logic
io.on('connection', (socket) => {
  const userId = socket.handshake.query.userId as string;
  if (userId) {
    socket.join(userId); // Put all user's devices in one room
    console.log(`User ${userId} connected`);
  }

  // When user starts a session on Web
  socket.on('start_focus', (data) => {
    // Broadcast to all other devices (Phone, Desktop Agent)
    io.to(userId).emit('focus_mode_activated', {
      goal: data.goal,
      endTime: Date.now() + (data.duration * 1000)
    });
  });

  socket.on('disconnect', () => console.log('Disconnected'));
});

const PORT = process.env.PORT || 3001;
httpServer.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

### Step 4: Secure Your API Key
Create a `.env` file on your server. **Never** push this file to GitHub.

```env
PORT=3001
API_KEY=your_gemini_api_key_here
DATABASE_URL=your_postgres_url
```

### Step 5: Connecting the Frontend
In your existing `Dashboard.tsx`, you would replace the local state logic with the socket connection:

```typescript
import { io } from "socket.io-client";

// Inside your Dashboard component:
useEffect(() => {
    const socket = io("https://your-backend-url.com", {
        query: { userId: "user_123" } // In a real app, get this from Auth
    });

    socket.on("focus_mode_activated", (data) => {
        // Trigger the block overlay on this device automatically
        setIsFocusing(true);
        setFocusGoal(data.goal);
    });

    return () => { socket.disconnect(); };
}, []);

const handleStartFocus = () => {
    // Tell the backend to tell ALL my devices to block apps
    socket.emit("start_focus", { goal: focusGoal, duration: focusDuration });
    // Proceed with local timer...
};
```

### Summary of Installation Steps
1.  **Backend:** Setup Node.js + Socket.io server.
2.  **Database:** Store the "Blocking State" so if a user refreshes the page, they are still blocked.
3.  **Security:** Move the Gemini API calls to the server so your `API_KEY` is hidden.
4.  **Deployment:** Deploy the backend to a cloud provider like **Railway** (easiest for Node/Postgres).
5.  **Environment Variables:** Add your `API_KEY` to the deployment settings on the cloud provider.

