import express from 'express';
import { createServer } from 'http';
import { Server } from 'socket.io';
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from 'dotenv';
import cors from 'cors';
import pg from 'pg';

// 1. Initialize environment
dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

const httpServer = createServer(app);
const io = new Server(httpServer, {
    cors: {
        origin: "*", // In production, replace with your frontend URL
        methods: ["GET", "POST"]
    }
});

// 2. Database Setup (PostgreSQL)
const pool = new pg.Pool({
    connectionString: process.env.DATABASE_URL,
    ssl: { rejectUnauthorized: false } // Required for many cloud providers like Supabase/Neon
});

// 3. AI Setup
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

// 4. API Routes
app.get('/health', (req, res) => res.send('FocusFlow Backend is Healthy'));

// Secure AI Route: Suggestions are fetched on server to hide API_KEY
app.get('/api/suggestions', async (req, res) => {
    try {
        const prompt = "Generate a list of 5 diverse and actionable productive alternatives to scrolling social media. Provide as JSON array with title and description.";
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            description: { type: Type.STRING }
                        },
                        required: ["title", "description"]
                    }
                }
            }
        });
        res.json(JSON.parse(response.text));
    } catch (error) {
        console.error("AI Error:", error);
        res.status(500).json({ error: "Failed to get suggestions" });
    }
});

// 5. Real-time WebSocket Logic
io.on('connection', (socket) => {
    const userId = socket.handshake.query.userId as string;

    if (userId) {
        socket.join(userId);
        console.log(`Device connected for user: ${userId}`);
    }

    // Handle Start Focus Session
    socket.on('session:start', async (data) => {
        const { goal, duration, appsBlocked } = data;

        // Save to DB
        try {
            await pool.query(
                'INSERT INTO focus_sessions (user_id, goal, duration, apps_blocked, status) VALUES ($1, $2, $3, $4, $5)',
                [userId, goal, duration, JSON.stringify(appsBlocked), 'active']
            );
        } catch (err) {
            console.error("DB Error on session start:", err);
        }

        // Notify all other devices belonging to this user
        socket.to(userId).emit('session:remote_start', {
            goal,
            duration,
            appsBlocked,
            startTime: Date.now()
        });
    });

    // Handle Stop Focus Session
    socket.on('session:stop', async () => {
        try {
            await pool.query(
                "UPDATE focus_sessions SET status = 'stopped' WHERE user_id = $1 AND status = 'active'",
                [userId]
            );
        } catch (err) {
            console.error("DB Error on session stop:", err);
        }

        socket.to(userId).emit('session:remote_stop');
    });

    socket.on('disconnect', () => {
        console.log(`Device disconnected for user: ${userId}`);
    });
});

const PORT = process.env.PORT || 3001;
httpServer.listen(PORT, () => {
    console.log(`>>> FocusFlow Backend active on port ${PORT}`);
});

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { io, Socket } from 'socket.io-client';
import { INITIAL_SOCIAL_APPS, BADGES } from '../constants';
import AppSelector from './AppSelector';
import InsightsChart from './InsightsChart';
import { getNewProductiveSuggestions } from '../services/geminiService';
import { ProductiveSuggestion, AppInfo, ChartDataPoint, FocusSession, UserProgress } from '../types';
import ProductiveSuggestions from './ProductiveSuggestions';
import { playBlockSound, playSound, SoundName } from '../utils/audioUtils';
import AppLauncher from './AppLauncher';
import UsagePage from './UsagePage';
import FocusSessionControl from './FocusSessionControl';
import Notification from './Notification';
import { createFocusBlockPageHTML, createDailyLimitBlockPageHTML } from '../utils/blockPageUtils';
import Features from './Features';
import FocusHistory from './FocusHistory';
import { useIdleTimer } from '../utils/idleTimer';
import AddAppModal from './AddAppModal';
import GlobeIcon from './icons/GlobeIcon';
import GamificationHub from './GamificationHub';
import SystemIntegrations from './SystemIntegrations';
import DistractionBreakdown from './DistractionBreakdown';
import { trackEvent } from '../utils/analytics';

// Types for new dynamic data structure
interface HourlyStats {
    [hour: number]: { focus: number, distraction: number };
}

interface TodayStats {
    date: string;
    hourly: HourlyStats;
}

interface DailyStats {
    [date: string]: { focus: number, distraction: number };
}

type InsightsView = 'day' | 'week' | 'month';
type MainView = 'dashboard' | 'usage';

interface DashboardProps {
    isSoundEnabled: boolean;
    userProgress: UserProgress;
    onUpdateProgress: (newProgress: UserProgress) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isSoundEnabled, userProgress, onUpdateProgress }) => {
    // Socket.io Client Implementation
    const socketRef = useRef<typeof Socket | null>(null);
    const BACKEND_URL = "http://localhost:3001"; // Update to your deployed Railway/Render URL

    const [apps, setApps] = useState<AppInfo[]>(() => {
        try {
            const savedApps = window.localStorage.getItem('focusFlowApps');
            return savedApps ? JSON.parse(savedApps) : INITIAL_SOCIAL_APPS;
        } catch (error) {
            console.error("Failed to parse apps from localStorage", error);
            return INITIAL_SOCIAL_APPS;
        }
    });

    const [appLimits, setAppLimits] = useState<{ [key: string]: number }>(() => {
        try {
            const savedLimits = window.localStorage.getItem('focusFlowAppLimits');
            return savedLimits ? JSON.parse(savedLimits) : {};
        } catch (error) {
            console.error("Failed to parse app limits from localStorage", error);
            return {};
        }
    });

    const [appUsage, setAppUsage] = useState<{ [key: string]: number }>(() => {
        try {
            const savedUsageData = window.localStorage.getItem('focusFlowAppUsage');
            if (!savedUsageData) return {};

            const { usage, date } = JSON.parse(savedUsageData);
            const today = new Date().toISOString().split('T')[0];

            return date === today ? usage : {};
        } catch (error) {
            console.error("Failed to parse app usage from localStorage", error);
            return {};
        }
    });

    const [productiveSuggestions, setProductiveSuggestions] = useState<ProductiveSuggestion[]>([]);
    const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(true);
    const [insightsView, setInsightsView] = useState<InsightsView>('week');
    const [currentView, setCurrentView] = useState<MainView>('dashboard');
    const [activeApp, setActiveApp] = useState<AppInfo | null>(null);
    const [isAddAppModalOpen, setIsAddAppModalOpen] = useState(false);

    // Dynamic focus data states
    const [dailyStats, setDailyStats] = useState<DailyStats>(() => {
        try {
            const saved = window.localStorage.getItem('focusFlowDailyStats');
            return saved ? JSON.parse(saved) : {};
        } catch (e) {
            console.error("Failed to load daily stats", e);
            return {};
        }
    });

    const [todayStats, setTodayStats] = useState<TodayStats>(() => {
        const todayStr = new Date().toISOString().split('T')[0];
        try {
            const saved = window.localStorage.getItem('focusFlowTodayStats');
            if (saved) {
                const parsed = JSON.parse(saved);
                if (parsed.date === todayStr) {
                    return parsed;
                }
            }
            return { date: todayStr, hourly: {} };
        } catch (e) {
            console.error("Failed to load today stats", e);
            return { date: todayStr, hourly: {} };
        }
    });

    const [focusHistory, setFocusHistory] = useState<FocusSession[]>(() => {
        try {
            const saved = window.localStorage.getItem('focusFlowHistory');
            return saved ? JSON.parse(saved) : [];
        } catch (e) {
            console.error("Failed to load history", e);
            return [];
        }
    });

    // Focus Session State
    const [isFocusing, setIsFocusing] = useState(false);
    const [isIdle, setIsIdle] = useState(false);
    const [idleTimeout, setIdleTimeout] = useState(300);
    const [focusApps, setFocusApps] = useState<string[]>([]);
    const [focusDuration, setFocusDuration] = useState(25 * 60);
    const [timeLeft, setTimeLeft] = useState(25 * 60);
    const [focusGoal, setFocusGoal] = useState('');
    const [syncToCalendar, setSyncToCalendar] = useState(false);
    const [sessionWasSynced, setSessionWasSynced] = useState(false);
    const [notification, setNotification] = useState<{message: string, type: 'success' | 'info' | 'calendar' | 'block' | 'achievement', app?: AppInfo, badgeName?: string} | null>(null);
    const [focusStartSound, setFocusStartSound] = useState<SoundName>('Bell');
    const [focusEndSound, setFocusEndSound] = useState<SoundName>('Chime');
    const focusIntervalRef = useRef<number | null>(null);
    const appWindowRef = useRef<Window | null>(null);
    const minutesCountedRef = useRef(0);

    // REAL-TIME SYNC: Initialize Socket connection
    useEffect(() => {
        const userId = "demo_user_123"; // In production, get from Auth context

        const socket = io(BACKEND_URL, {
            query: { userId },
            transports: ['websocket']
        });

        socket.on('connect', () => console.log("Connected to FocusFlow Sync Server"));

        // Listen for sessions started on other devices (Phone/Tablet)
        socket.on('session:remote_start', (data: any) => {
            setFocusGoal(data.goal);
            setFocusDuration(data.duration);
            setFocusApps(data.appsBlocked);

            const elapsed = Math.floor((Date.now() - data.startTime) / 1000);
            const remaining = Math.max(0, data.duration - elapsed);
            setTimeLeft(remaining);
            setIsFocusing(true);

            setNotification({ message: "Focus Session started remotely on another device.", type: 'info' });
            setTimeout(() => setNotification(null), 5000);
        });

        socket.on('session:remote_stop', () => {
            setIsFocusing(false);
            if (focusIntervalRef.current) clearInterval(focusIntervalRef.current);
            setNotification({ message: "Session stopped from another device.", type: 'info' });
            setTimeout(() => setNotification(null), 5000);
        });

        socketRef.current = socket;

        return () => {
            socket.disconnect();
        };
    }, []);

    // Idle timer hook
    useIdleTimer({
        onIdle: () => {
            if (isFocusing && !isIdle) {
                setIsIdle(true);
            }
        },
        onActive: () => {
            if (isFocusing && isIdle) {
                setIsIdle(false);
            }
        },
        timeout: idleTimeout,
        enabled: isFocusing && idleTimeout > 0,
    });

    useEffect(() => {
        if (!isFocusing) {
            if (isIdle) setIsIdle(false);
            return;
        }

        if (isIdle) {
            if (focusIntervalRef.current) {
                clearInterval(focusIntervalRef.current);
                focusIntervalRef.current = null;
                setNotification({ message: 'Session paused due to inactivity. Move your mouse or type to resume.', type: 'info' });
            }
        } else {
            if (!focusIntervalRef.current && timeLeft > 0) {
                focusIntervalRef.current = window.setInterval(() => {
                    setTimeLeft(prev => prev - 1);
                }, 1000);
                setNotification({ message: 'Focus session resumed.', type: 'info' });
                setTimeout(() => setNotification(null), 4000);
            }
        }
    }, [isFocusing, isIdle]);

    const updateFocusStats = useCallback((minutes: number) => {
        const now = new Date();
        const todayStr = now.toISOString().split('T')[0];
        const currentHour = now.getHours();

        setDailyStats(prev => {
            const newStats = { ...prev };
            if (!newStats[todayStr]) newStats[todayStr] = { focus: 0, distraction: 0 };
            newStats[todayStr].focus += minutes;
            return newStats;
        });

        setTodayStats(prev => {
            const newStats = { ...prev, hourly: { ...prev.hourly } };
            if (newStats.date !== todayStr) {
                newStats.date = todayStr;
                newStats.hourly = {};
            }
            if (!newStats.hourly[currentHour]) newStats.hourly[currentHour] = { focus: 0, distraction: 0 };
            newStats.hourly[currentHour].focus += minutes;
            return newStats;
        });
    }, []);

    useEffect(() => {
        if (isFocusing && timeLeft > 0 && timeLeft < focusDuration) {
            const elapsed = focusDuration - timeLeft;
            const currentMinutes = Math.floor(elapsed / 60);

            if (currentMinutes > minutesCountedRef.current) {
                 const diff = currentMinutes - minutesCountedRef.current;
                 if (diff > 0) {
                     updateFocusStats(diff);
                     minutesCountedRef.current = currentMinutes;
                 }
            }
        }
    }, [timeLeft, isFocusing, focusDuration, updateFocusStats]);

    useEffect(() => {
        window.localStorage.setItem('focusFlowApps', JSON.stringify(apps));
    }, [apps]);

    useEffect(() => {
        window.localStorage.setItem('focusFlowAppLimits', JSON.stringify(appLimits));
    }, [appLimits]);

    useEffect(() => {
        const today = new Date().toISOString().split('T')[0];
        window.localStorage.setItem('focusFlowAppUsage', JSON.stringify({ usage: appUsage, date: today }));
    }, [appUsage]);

    useEffect(() => {
        window.localStorage.setItem('focusFlowDailyStats', JSON.stringify(dailyStats));
    }, [dailyStats]);

    useEffect(() => {
        window.localStorage.setItem('focusFlowTodayStats', JSON.stringify(todayStats));
    }, [todayStats]);

    useEffect(() => {
        window.localStorage.setItem('focusFlowHistory', JSON.stringify(focusHistory));
    }, [focusHistory]);

    useEffect(() => {
        const fetchSuggestions = async () => {
            setIsLoadingSuggestions(true);
            const suggestions = await getNewProductiveSuggestions();
            setProductiveSuggestions(suggestions);
            setIsLoadingSuggestions(false);
        };
        fetchSuggestions();
    }, []);

    const allCategories = useMemo(() => {
        const categories = new Set(apps.map(app => app.category));
        return Array.from(categories).sort();
    }, [apps]);

    const handleAddNewApp = (newApp: { name: string; url: string; category: string }) => {
        const newAppInfo: AppInfo = {
            id: `custom-${new Date().getTime()}`,
            name: newApp.name,
            url: newApp.url,
            category: newApp.category,
            Icon: GlobeIcon,
        };
        setApps(prevApps => [...prevApps, newAppInfo]);
        setIsAddAppModalOpen(false);
    };

    const handleUpdateAppCategory = (appId: string, newCategory: string) => {
        setApps(prevApps => prevApps.map(app => app.id === appId ? { ...app, category: newCategory } : app));
    };

    const handleFocusEnd = useCallback((wasStopped = false) => {
        setIsFocusing(false);
        if (focusIntervalRef.current) {
            clearInterval(focusIntervalRef.current);
            focusIntervalRef.current = null;
        }

        // SYNC: Notify backend that we stopped
        if (socketRef.current) {
            socketRef.current.emit('session:stop');
        }

        if (isSoundEnabled) playSound(focusEndSound);

        const minutesFocused = Math.floor((focusDuration - timeLeft) / 60);

        if (wasStopped) {
            trackEvent('session_stopped', { goal: focusGoal, minutesCompleted: minutesFocused });
        } else {
            trackEvent('session_completed', { goal: focusGoal, minutesCompleted: minutesFocused });
        }

        if (minutesFocused > 0) {
            const now = new Date();
            const todayStr = now.toISOString().split('T')[0];
            const pointsEarned = Math.floor(minutesFocused * 1);
            const newTotalFocusMinutes = userProgress.totalFocusMinutes + minutesFocused;
            const newSessionsCompleted = userProgress.sessionsCompleted + 1;

            let newStreak = userProgress.streak;
            if (userProgress.lastActiveDate !== todayStr) {
                const yesterday = new Date();
                yesterday.setDate(yesterday.getDate() - 1);
                const yesterdayStr = yesterday.toISOString().split('T')[0];

                if (userProgress.lastActiveDate === yesterdayStr) newStreak += 1;
                else newStreak = 1;
            }

            const currentBadgeIds = new Set(userProgress.badges);
            const newBadges: string[] = [];

            const tempStats: UserProgress = {
                ...userProgress,
                totalFocusMinutes: newTotalFocusMinutes,
                sessionsCompleted: newSessionsCompleted,
                streak: newStreak,
                points: userProgress.points + pointsEarned
            };

            BADGES.forEach(badge => {
                if (!currentBadgeIds.has(badge.id) && badge.condition(tempStats)) {
                    newBadges.push(badge.id);
                    currentBadgeIds.add(badge.id);
                }
            });

            onUpdateProgress({ ...tempStats, badges: Array.from(currentBadgeIds), lastActiveDate: todayStr });

            newBadges.forEach((badgeId, index) => {
                const badge = BADGES.find(b => b.id === badgeId);
                if (badge) {
                    setTimeout(() => {
                        setNotification({ message: `Badge Unlocked: ${badge.name}`, type: 'achievement', badgeName: badge.name });
                        if (isSoundEnabled) playSound('Chime');
                    }, 1000 + (index * 3000));
                }
            });
        }

        setFocusHistory(prev => [...prev, {
            id: new Date().toISOString(),
            goal: focusGoal,
            duration: focusDuration,
            completedDuration: focusDuration - timeLeft,
            date: new Date().toISOString(),
            appsBlocked: focusApps,
            status: wasStopped ? 'stopped' : 'completed',
            interventions: []
        }]);

        setNotification({ 
            message: wasStopped ? "Session stopped early." : `You completed a ${minutesFocused}-minute focus session.`, 
            type: wasStopped ? 'info' : 'success' 
        });

        setFocusGoal('');
        setSyncToCalendar(false);
        setSessionWasSynced(false);
        setIsIdle(false);
        setTimeout(() => setNotification(null), 5000);
    }, [focusDuration, timeLeft, focusGoal, isSoundEnabled, focusEndSound, focusApps, userProgress, onUpdateProgress]);

    useEffect(() => {
        if (isFocusing && timeLeft <= 0) handleFocusEnd();
    }, [timeLeft, isFocusing, handleFocusEnd]);

    const handleSetAppLimit = (appId: string, limit: number) => {
        setAppLimits(prev => ({ ...prev, [appId]: limit }));
    };

    const handleToggleFocusApp = (appId: string) => {
        setFocusApps(prev => prev.includes(appId) ? prev.filter(id => id !== appId) : [...prev, appId]);
    };

    const handleStartFocus = () => {
        if (focusIntervalRef.current) clearInterval(focusIntervalRef.current);
        setTimeLeft(focusDuration);
        setIsFocusing(true);
        setIsIdle(false);
        setSessionWasSynced(syncToCalendar);
        minutesCountedRef.current = 0;

        // SYNC: Notify backend to block other devices
        if (socketRef.current) {
            socketRef.current.emit('session:start', {
                goal: focusGoal,
                duration: focusDuration,
                appsBlocked: focusApps
            });
        }

        if (isSoundEnabled) playSound(focusStartSound);

        focusIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
        setNotification({ message: 'Focus session started globally.', type: 'info' });
        setTimeout(() => setNotification(null), 5000);
    };

    const handleStopFocus = () => handleFocusEnd(true);

    const handleAppLaunchAttempt = (appId: string) => {
        const app = apps.find(a => a.id === appId);
        if (!app) return;

        if (isFocusing && focusApps.includes(appId)) {
            if (isSoundEnabled) playBlockSound();
            const blockPageHTML = createFocusBlockPageHTML(focusGoal, timeLeft);
            const newWindow = window.open('', '_blank');
            if (newWindow) { newWindow.document.write(blockPageHTML); newWindow.document.close(); }
            setNotification({ message: `This app is blocked during focus.`, type: 'block', app: app });
            return;
        }

        const limitInSeconds = (appLimits[appId] || 0) * 60;
        const usageInSeconds = appUsage[appId] || 0;

        if (limitInSeconds > 0 && usageInSeconds >= limitInSeconds) {
            if (isSoundEnabled) playBlockSound();
            const blockPageHTML = createDailyLimitBlockPageHTML(app.name);
            const newWindow = window.open('', '_blank');
            if (newWindow) { newWindow.document.write(blockPageHTML); newWindow.document.close(); }
            setNotification({ message: `Daily limit reached.`, type: 'block', app: app });
        } else {
            setActiveApp(app);
            appWindowRef.current = window.open(app.url, '_blank', 'noopener,noreferrer');
            setCurrentView('usage');
        }
    };

    const handleLeaveUsagePage = useCallback((timeSpentSeconds: number) => {
        if (!activeApp) return;
        const usageInMinutes = Math.round(timeSpentSeconds / 60);
        if (usageInMinutes > 0) {
            const now = new Date();
            const todayStr = now.toISOString().split('T')[0];
            const currentHour = now.getHours();

            setDailyStats(prev => {
                const newStats = { ...prev };
                if (!newStats[todayStr]) newStats[todayStr] = { focus: 0, distraction: 0 };
                newStats[todayStr].distraction += usageInMinutes;
                return newStats;
            });

            setTodayStats(prev => {
                const newStats = { ...prev, hourly: { ...prev.hourly } };
                if (newStats.date !== todayStr) { newStats.date = todayStr; newStats.hourly = {}; }
                if (!newStats.hourly[currentHour]) newStats.hourly[currentHour] = { focus: 0, distraction: 0 };
                newStats.hourly[currentHour].distraction += usageInMinutes;
                return newStats;
            });
        }

        setAppUsage(prev => ({ ...prev, [activeApp.id]: (prev[activeApp.id] || 0) + timeSpentSeconds }));
        if (appWindowRef.current && !appWindowRef.current.closed) appWindowRef.current.close();
        appWindowRef.current = null;
        setCurrentView('dashboard');
        setActiveApp(null);
    }, [activeApp]);

    const chartData = useMemo(() => {
        const now = new Date();
        if (insightsView === 'day') {
            const data: ChartDataPoint[] = [];
            for (let hour = 6; hour <= 22; hour++) {
                const stats = todayStats.hourly[hour] || { focus: 0, distraction: 0 };
                const period = hour < 12 ? 'a' : 'p';
                let displayHour = hour % 12 || 12;
                data.push({ hour: `${displayHour}${period}`, ...stats });
            }
            return data;
        }
        if (insightsView === 'week') {
            const data: ChartDataPoint[] = [];
            const dayMap = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
            const currentDayOfWeek = now.getDay();
            for (let i = 0; i < 7; i++) {
                const dayOfView = new Date(now);
                dayOfView.setDate(now.getDate() - (currentDayOfWeek - i));
                const dateStr = dayOfView.toISOString().split('T')[0];
                const stats = dailyStats[dateStr] || { focus: 0, distraction: 0 };
                data.push({ day: dayMap[i], ...stats });
            }
            return data;
        }
        return [];
    }, [insightsView, dailyStats, todayStats]);

    const renderChart = () => <InsightsChart data={chartData} xAxisDataKey={insightsView === 'day' ? 'hour' : 'day'} />;

    const ViewButton: React.FC<{view: InsightsView, label: string}> = ({ view, label }) => (
        <button onClick={() => setInsightsView(view)} className={`px-3 py-1 text-sm font-medium rounded-md transition-colors ${insightsView === view ? 'bg-brand-accent text-white' : 'text-gray-300 hover:bg-gray-600'}`}>
            {label}
        </button>
    );

    if (currentView === 'usage' && activeApp) {
        return <UsagePage app={activeApp} timeLimitSeconds={(appLimits[activeApp.id] || 0) * 60} timeUsedSeconds={appUsage[activeApp.id] || 0} onLeave={handleLeaveUsagePage} isBlockedByFocus={isFocusing && focusApps.includes(activeApp.id)} />;
    }

    return (
        <div className="space-y-8 p-4">
            {notification && <Notification message={notification.message} type={notification.type} app={notification.app} onClose={() => setNotification(null)} badgeName={notification.badgeName} />}
            <AddAppModal isOpen={isAddAppModalOpen} onClose={() => setIsAddAppModalOpen(false)} onAddApp={handleAddNewApp} existingCategories={allCategories} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-brand-secondary p-6 rounded-lg shadow-lg">
                    <div className="flex justify-between items-start mb-2">
                        <h1 className="text-3xl font-bold">Digital Wellbeing Hub</h1>
                        <span className="bg-green-500/20 text-green-400 text-[10px] font-bold px-2 py-1 rounded-full flex items-center">
                            <span className="w-1.5 h-1.5 bg-green-500 rounded-full mr-1.5 animate-pulse"></span>
                            SYNC ACTIVE
                        </span>
                    </div>
                    <p className="text-gray-400 mb-6">Real-time synchronization enabled. Session state will reflect across all devices.</p>

                    <div className="space-y-8">
                       <AppSelector apps={apps} limits={appLimits} onSetLimit={handleSetAppLimit} usage={appUsage} focusApps={focusApps} onToggleFocusApp={handleToggleFocusApp} isFocusing={isFocusing} onUpdateAppCategory={handleUpdateAppCategory} onOpenAddAppModal={() => setIsAddAppModalOpen(true)} />
                       <FocusSessionControl isFocusing={isFocusing} onStart={handleStartFocus} onStop={handleStopFocus} timeLeft={timeLeft} hasSelectedApps={focusApps.length > 0} goal={focusGoal} onGoalChange={setFocusGoal} duration={focusDuration} onDurationChange={setFocusDuration} syncToCalendar={syncToCalendar} onSyncToCalendarChange={setSyncToCalendar} startSound={focusStartSound} onStartSoundChange={setFocusStartSound} endSound={focusEndSound} onEndSoundChange={setFocusEndSound} isIdle={isIdle} idleTimeout={idleTimeout} onIdleTimeoutChange={setIdleTimeout} />
                    </div>
                </div>

                <div className="lg:col-span-1 space-y-8">
                   <GamificationHub progress={userProgress} />
                   <SystemIntegrations />
                   <div className="bg-brand-secondary p-6 rounded-lg shadow-lg">
                        <div className="flex justify-between items-center mb-4">
                            <h2 className="text-xl font-bold">Focus Insights</h2>
                            <div className="flex space-x-1 bg-gray-800 p-1 rounded-lg">
                               <ViewButton view="day" label="Day" />
                               <ViewButton view="week" label="Week" />
                            </div>
                        </div>
                        {renderChart()}
                        <DistractionBreakdown appUsage={appUsage} apps={apps} />
                    </div>
                    <ProductiveSuggestions suggestions={productiveSuggestions} isLoading={isLoadingSuggestions} />
                    <FocusHistory sessions={focusHistory} apps={apps} />
                </div>
            </div>
            <AppLauncher apps={apps} onAppClick={handleAppLaunchAttempt} />
            <Features />
        </div>
    );
};

