import express from 'express';
import { createServer } from 'http';
import { Server } from 'socket.io';
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from 'dotenv';
import cors from 'cors';
import pg from 'pg';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

const httpServer = createServer(app);
const io = new Server(httpServer, {
    cors: { origin: "*", methods: ["GET", "POST"] }
});

const pool = new pg.Pool({
    connectionString: process.env.DATABASE_URL,
    ssl: { rejectUnauthorized: false }
});

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

// Tracking connected devices per user
const userDevices: Record<string, Set<string>> = {};

io.on('connection', (socket) => {
    const userId = socket.handshake.query.userId as string;
    const platform = socket.handshake.query.platform as string || 'web';

    if (userId) {
        socket.join(userId);
        if (!userDevices[userId]) userDevices[userId] = new Set();
        userDevices[userId].add(socket.id);

        console.log(`[Connect] User: ${userId} | Platform: ${platform} | Socket: ${socket.id}`);

        // Let all user devices know a new one joined
        io.to(userId).emit('device:status', { 
            deviceId: socket.id, 
            platform, 
            status: 'online',
            totalDevices: userDevices[userId].size 
        });
    }

    // Command: Start Blocking across all devices
    socket.on('session:start', async (data) => {
        const { goal, duration, appsBlocked } = data;
        console.log(`[Focus Start] User ${userId} blocking: ${appsBlocked.join(', ')}`);

        // 1. Persist to DB
        try {
            await pool.query(
                'INSERT INTO focus_sessions (user_id, goal, duration, apps_blocked, status) VALUES ($1, $2, $3, $4, $5)',
                [userId, goal, duration, JSON.stringify(appsBlocked), 'active']
            );
        } catch (err) { console.error("DB Error:", err); }

        // 2. Broadcast BLOCKED command to Windows/Mobile agents
        socket.to(userId).emit('command:block_apps', {
            apps: appsBlocked,
            duration: duration,
            goal: goal
        });
    });

    // Command: Stop Blocking
    socket.on('session:stop', () => {
        console.log(`[Focus Stop] User ${userId}`);
        socket.to(userId).emit('command:unblock_apps');
    });

    socket.on('disconnect', () => {
        if (userId && userDevices[userId]) {
            userDevices[userId].delete(socket.id);
            io.to(userId).emit('device:status', { 
                deviceId: socket.id, 
                platform, 
                status: 'offline',
                totalDevices: userDevices[userId].size 
            });
        }
    });
});

const PORT = process.env.PORT || 3001;
httpServer.listen(PORT, () => console.log(`>>> FocusFlow Hub on port ${PORT}`));

/**
 * FocusFlow Windows Agent
 * -----------------------
 * This script runs on your Windows machine and kills distractions.
 * 
 * SETUP:
 * 1. Install Node.js
 * 2. npm install socket.io-client
 * 3. node WINDOWS_AGENT_SETUP.js
 */

const { io } = require("socket.io-client");
const { exec } = require("child_process");

const SERVER_URL = "http://localhost:3001"; // Change to your public server URL
const USER_ID = "demo_user_123"; // Must match your web dashboard login

const socket = io(SERVER_URL, {
    query: { userId: USER_ID, platform: 'windows' }
});

// Map of FocusFlow IDs to Windows Executable Names
const APP_PROCESS_MAP = {
    'twitter': 'Twitter.exe',
    'instagram': 'Instagram.exe',
    'facebook': 'Facebook.exe',
    'chrome': 'chrome.exe', // Be careful blocking browsers!
    'whatsapp': 'WhatsApp.exe'
};

let activeInterval = null;
let appsToBlock = [];

console.log(">>> FocusFlow Windows Guard Started...");
console.log(`>>> Connecting to Hub: ${SERVER_URL}`);

socket.on("connect", () => {
    console.log("Successfully connected to FocusFlow Hub.");
});

socket.on("command:block_apps", (data) => {
    console.log(`!!! FOCUS MODE ACTIVATED: ${data.goal}`);
    appsToBlock = data.apps;

    // Start the enforcement loop (runs every 5 seconds)
    if (activeInterval) clearInterval(activeInterval);

    activeInterval = setInterval(() => {
        appsToBlock.forEach(appId => {
            const processName = APP_PROCESS_MAP[appId];
            if (processName) {
                // Execute Windows TaskKill command
                exec(`taskkill /F /IM ${processName} /T`, (err) => {
                    if (!err) console.log(`[Blocked] Terminated ${processName} to keep you focused on ${data.goal}`);
                });
            }
        });
    }, 5000);
});

socket.on("command:unblock_apps", () => {
    console.log(">>> Session ended. Unblocking apps.");
    if (activeInterval) {
        clearInterval(activeInterval);
        activeInterval = null;
    }
});

socket.on("disconnect", () => {
    console.log("Disconnected from Hub. Safety unblock engaged.");
    if (activeInterval) clearInterval(activeInterval);
});

