                                                </select>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="flex items-center space-x-3">
                                        <div className="text-right">
                                            <label className="block text-[10px] text-gray-500 uppercase font-bold mb-1">Limit (min)</label>
