                                                className="w-16 bg-gray-700 border border-gray-600 rounded px-2 py-1 text-sm text-white focus:outline-none focus:ring-2 focus:ring-brand-accent transition-all"
                                            />
                                        </div>
                                    </div>
                                </div>
                            ))}
